# Starlette internals (simplified)
class BackgroundTasks:
    def __init__(self):
        self.tasks = []

    def add_task(self, func, *args, **kwargs):
        self.tasks.append(BackgroundTask(func, *args, **kwargs))

    async def __call__(self):
        for task in self.tasks:
            await task()  # Awaits async tasks; runs sync tasks in thread pool

from functools import wraps
from typing import Callable, Any

def safe_background_task(func: Callable) -> Callable:
    """Decorator that catches and logs all exceptions from background tasks."""
    @wraps(func)
    async def wrapper(*args, **kwargs):
        try:
            if asyncio.iscoroutinefunction(func):
                await func(*args, **kwargs)
            else:
                func(*args, **kwargs)
        except Exception as exc:
            logger.error(
                f"Background task '{func.__name__}' failed: {exc}",
                exc_info=True,
                extra={"args": args, "kwargs": kwargs}
            )
    return wrapper

